export interface Question {
  id: string;
  text: string;
  options: {
    label: string;
    text: string;
  }[];
  correctAnswer: string;
}

export interface Test {
  id: string;
  title: string;
  questions: Question[];
  createdAt: number;
  timerMinutes: number;
  creatorId: string;
}

export interface TestResult {
  id: string;
  testId: string;
  testTitle: string;
  studentId: string;
  studentName: string;
  score: number;
  totalQuestions: number;
  timestamp: number;
  incorrectQuestions: string[]; // IDs of missed questions
  aiFeedback?: string;
}

export interface User {
  id: string;
  name: string;
  role: 'teacher' | 'student';
  password?: string;
}

export enum Theme {
  LIGHT = 'light',
  DARK = 'dark'
}

export type ViewState = 'home' | 'login' | 'teacher-dash' | 'student-dash' | 'test-creator' | 'test-taking' | 'result-view';

import { GoogleGenAI, Type } from "@google/genai";
import { Question } from "../types";

export const generateQuestionsWithGemini = async (text: string, count: number): Promise<Question[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Based on the following study text, generate exactly ${count} multiple-choice questions. 
    Each question must have 4 options (A, B, C, D). 
    TEXT:
    ${text}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            text: { type: Type.STRING },
            options: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  label: { type: Type.STRING },
                  text: { type: Type.STRING }
                },
                required: ["label", "text"]
              }
            },
            correctAnswer: { type: Type.STRING }
          },
          required: ["text", "options", "correctAnswer"]
        }
      }
    }
  });

  const rawQuestions = JSON.parse(response.text || "[]");
  return rawQuestions.map((q: any, index: number) => ({
    ...q,
    id: `q-${index + 1}`
  }));
};

export const getAIStudyFeedback = async (score: number, missedQuestions: string[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `A student scored ${score}% on a test. They missed questions related to these topics: ${missedQuestions.join(", ")}. 
    Provide encouraging, brief, and actionable study advice in 3 bullet points. Focus on what they should study next.`,
  });
  return response.text || "Keep studying and focus on the areas where you missed questions!";
};

import React, { useState, useEffect, useRef } from 'react';
import { Question, Theme, ViewState, User, Test, TestResult } from './types';
import { generateQuestionsWithGemini, getAIStudyFeedback } from './services/geminiService';

const App: React.FC = () => {
  // State: Core Navigation & Auth
  const [view, setView] = useState<ViewState>('home');
  const [role, setRole] = useState<'teacher' | 'student' | null>(null);
  const [user, setUser] = useState<User | null>(null);
  const [theme, setTheme] = useState<Theme>(Theme.LIGHT);

  // State: Data Persistence (Simulated DB)
  const [tests, setTests] = useState<Test[]>([]);
  const [results, setResults] = useState<TestResult[]>([]);

  // State: Active Workflows
  const [activeTest, setActiveTest] = useState<Test | null>(null);
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [timeLeft, setTimeLeft] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);

  // Refs for Scroll/PDF
  const questionRefs = useRef<Record<string, HTMLDivElement | null>>({});
  const timerRef = useRef<number | null>(null);

  // Initialize Data
  useEffect(() => {
    const savedTests = localStorage.getItem('qs_tests');
    const savedResults = localStorage.getItem('qs_results');
    const savedTheme = localStorage.getItem('theme') as Theme;

    if (savedTests) setTests(JSON.parse(savedTests));
    if (savedResults) setResults(JSON.parse(savedResults));
    if (savedTheme) {
      setTheme(savedTheme);
      document.documentElement.classList.toggle('dark', savedTheme === Theme.DARK);
    }
  }, []);

  // Persistence Hooks
  useEffect(() => {
    localStorage.setItem('qs_tests', JSON.stringify(tests));
  }, [tests]);

  useEffect(() => {
    localStorage.setItem('qs_results', JSON.stringify(results));
  }, [results]);

  // Timer Logic
  useEffect(() => {
    if (view === 'test-taking' && timeLeft > 0) {
      timerRef.current = window.setInterval(() => {
        setTimeLeft(prev => {
          if (prev <= 1) {
            handleTestSubmit();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [view, timeLeft]);

  // --- Handlers ---

  const toggleTheme = () => {
    const newTheme = theme === Theme.LIGHT ? Theme.DARK : Theme.LIGHT;
    setTheme(newTheme);
    localStorage.setItem('theme', newTheme);
    document.documentElement.classList.toggle('dark', newTheme === Theme.DARK);
  };

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const name = formData.get('name') as string;
    const id = formData.get('id') as string;
    const password = formData.get('password') as string;

    if (role === 'teacher') {
      if (password !== '1996') {
        setError('Incorrect Teacher Password.');
        return;
      }
    }

    const newUser: User = { id, name, role: role! };
    setUser(newUser);
    setError(null);
    setView(role === 'teacher' ? 'teacher-dash' : 'student-dash');
  };

  const createTest = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const text = formData.get('text') as string;
    const count = Number(formData.get('count'));
    const time = Number(formData.get('timer'));
    const title = formData.get('title') as string;

    if (text.length < 100) {
      setError('Material is too short.');
      return;
    }

    setIsGenerating(true);
    setError(null);

    try {
      const qs = await generateQuestionsWithGemini(text, count);
      const newTest: Test = {
        id: `t-${Date.now()}`,
        title: title || `Test ${tests.length + 1}`,
        questions: qs,
        createdAt: Date.now(),
        timerMinutes: time,
        creatorId: user!.id
      };
      setTests([newTest, ...tests]);
      setView('teacher-dash');
    } catch (err) {
      setError('Generation failed. Check API key/Text.');
    } finally {
      setIsGenerating(false);
    }
  };

  const startTest = (test: Test) => {
    setActiveTest(test);
    setAnswers({});
    setTimeLeft(test.timerMinutes * 60);
    setView('test-taking');
    setAiAnalysis(null);
  };

  const handleTestSubmit = async () => {
    if (!activeTest) return;

    let correct = 0;
    const missed: string[] = [];
    activeTest.questions.forEach(q => {
      if (answers[q.id] === q.correctAnswer) {
        correct++;
      } else {
        missed.push(q.text);
      }
    });

    const score = Math.round((correct / activeTest.questions.length) * 100);

    // AI Analysis
    const feedback = await getAIStudyFeedback(score, missed.slice(0, 3));

    const result: TestResult = {
      id: `r-${Date.now()}`,
      testId: activeTest.id,
      testTitle: activeTest.title,
      studentId: user!.id,
      studentName: user!.name,
      score,
      totalQuestions: activeTest.questions.length,
      timestamp: Date.now(),
      incorrectQuestions: missed,
      aiFeedback: feedback
    };

    setResults([result, ...results]);
    setAiAnalysis(feedback);
    setView('result-view');
  };

  const downloadPDF = () => {
    if (!activeTest) return;
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF();
    const dateStr = new Date().toLocaleDateString();

    doc.setFontSize(22);
    doc.text(activeTest.title, 20, 25);
    doc.setFontSize(10);
    doc.text(`Student: ${user?.name || 'N/A'} | ID: ${user?.id || 'N/A'} | Date: ${dateStr}`, 20, 32);
    doc.setDrawColor(200, 200, 200);
    doc.line(20, 35, 190, 35);

    let y = 45;
    activeTest.questions.forEach((q, i) => {
      if (y > 270) {
        // Footer before new page
        doc.setFontSize(8);
        doc.text(`Page ${doc.internal.getNumberOfPages()}`, 105, 290, { align: 'center' });
        doc.addPage();
        y = 20;
      }
      doc.setFontSize(11);
      doc.setFont('helvetica', 'bold');
      const lines = doc.splitTextToSize(`${i + 1}. ${q.text}`, 170);
      doc.text(lines, 20, y);
      y += (lines.length * 6);

      doc.setFont('helvetica', 'normal');
      q.options.forEach(opt => {
        doc.text(`${opt.label}) ${opt.text}`, 25, y);
        y += 6;
      });
      y += 4;
    });

    // Final Footer
    doc.setFontSize(8);
    doc.text(`Generated by QuickStudy LMS | Page ${doc.internal.getNumberOfPages()}`, 105, 290, { align: 'center' });
    doc.save(`${activeTest.title.replace(/\s+/g, '_')}_test.pdf`);
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s < 10 ? '0' : ''}${s}`;
  };

  // --- Render Components ---

  const Home = () => (
    <div className="flex flex-col items-center justify-center min-h-[80vh] text-center space-y-8 animate-in fade-in duration-700">
      <div className="space-y-4">
        <h1 className="text-5xl font-black tracking-tighter bg-gradient-to-r from-blue-600 to-indigo-600 bg-clip-text text-transparent">
          QuickStudy LMS
        </h1>
        <p className="text-xl opacity-70 max-w-md mx-auto">
          The intelligent bridge between teaching material and student success.
        </p>
      </div>
      <div className="flex flex-col sm:flex-row gap-4 w-full max-w-md px-4">
        <button 
          onClick={() => { setRole('teacher'); setView('login'); }}
          className="flex-1 py-4 bg-[var(--primary)] text-white rounded-2xl font-bold shadow-xl hover:scale-105 transition-all"
        >
          I am a Teacher
        </button>
        <button 
          onClick={() => { setRole('student'); setView('login'); }}
          className="flex-1 py-4 bg-white border-2 border-[var(--primary)] text-[var(--primary)] rounded-2xl font-bold shadow-xl hover:scale-105 transition-all"
        >
          I am a Student
        </button>
      </div>
    </div>
  );

  const Login = () => (
    <div className="max-w-md mx-auto py-12 animate-in slide-in-from-bottom-4 duration-500">
      <div className="q-card">
        <h2 className="text-2xl font-bold mb-6">
          {role === 'teacher' ? 'Teacher Portal Login' : 'Student Access'}
        </h2>
        <form onSubmit={handleLogin} className="space-y-4">
          <div>
            <label className="block text-sm font-medium mb-1">Full Name</label>
            <input required name="name" type="text" className="w-full p-3 border rounded-lg bg-[var(--bg)] outline-none focus:ring-2 focus:ring-blue-500" placeholder="John Doe" />
          </div>
          <div>
            <label className="block text-sm font-medium mb-1">{role === 'teacher' ? 'Staff ID' : 'Student ID'}</label>
            <input required name="id" type="text" className="w-full p-3 border rounded-lg bg-[var(--bg)] outline-none focus:ring-2 focus:ring-blue-500" placeholder="ID-12345" />
          </div>
          {role === 'teacher' && (
            <div>
              <label className="block text-sm font-medium mb-1">Passphrase (Initial: 1996)</label>
              <input required name="password" type="password" className="w-full p-3 border rounded-lg bg-[var(--bg)] outline-none focus:ring-2 focus:ring-blue-500" />
            </div>
          )}
          {error && <p className="text-red-500 text-sm">{error}</p>}
          <div className="flex gap-2">
            <button type="button" onClick={() => setView('home')} className="flex-1 py-3 bg-gray-100 dark:bg-gray-800 rounded-lg font-medium">Cancel</button>
            <button type="submit" className="flex-2 py-3 bg-[var(--primary)] text-white rounded-lg font-bold px-8">Login</button>
          </div>
        </form>
      </div>
    </div>
  );

  const TeacherDash = () => {
    const myTests = tests.filter(t => t.creatorId === user?.id);
    const classResults = results; // For demo, all teachers see all results, but filterable in real apps

    return (
      <div className="space-y-8 animate-in fade-in">
        <div className="flex justify-between items-center">
          <h2 className="text-2xl font-bold">Teacher Dashboard</h2>
          <button onClick={() => setView('test-creator')} className="px-6 py-2 bg-[var(--primary)] text-white rounded-full font-bold">+ New Test</button>
        </div>

        <div className="grid md:grid-cols-2 gap-8">
          {/* Tests Managed */}
          <div className="space-y-4">
            <h3 className="text-lg font-semibold opacity-70 uppercase tracking-wider text-xs">Your Tests</h3>
            {myTests.length === 0 ? <p className="opacity-50 italic">No tests created yet.</p> : myTests.map(t => (
              <div key={t.id} className="q-card p-4 flex justify-between items-center">
                <div>
                  <p className="font-bold">{t.title}</p>
                  <p className="text-xs opacity-50">{t.questions.length} Questions | {t.timerMinutes}m</p>
                </div>
                <button onClick={() => { setActiveTest(t); downloadPDF(); }} className="text-blue-500 hover:underline text-sm">PDF</button>
              </div>
            ))}
          </div>

          {/* Student Gradebook */}
          <div className="space-y-4">
            <h3 className="text-lg font-semibold opacity-70 uppercase tracking-wider text-xs">Student Performance</h3>
            {classResults.length === 0 ? <p className="opacity-50 italic">Waiting for submissions...</p> : classResults.map(r => (
              <div key={r.id} className="q-card p-4 border-l-4 border-blue-500">
                <div className="flex justify-between">
                  <span className="font-bold text-sm">{r.studentName} ({r.studentId})</span>
                  <span className={`font-black ${r.score >= 70 ? 'text-green-500' : 'text-red-500'}`}>{r.score}%</span>
                </div>
                <p className="text-xs opacity-60 mt-1">Test: {r.testTitle}</p>
                <p className="text-[10px] opacity-40">{new Date(r.timestamp).toLocaleString()}</p>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  };

  const StudentDash = () => {
    const myHistory = results.filter(r => r.studentId === user?.id);
    const availableTests = tests; // Students can take any test available

    return (
      <div className="space-y-8 animate-in fade-in">
        <div className="bg-gradient-to-r from-blue-500 to-indigo-600 p-8 rounded-3xl text-white shadow-xl">
          <h2 className="text-3xl font-bold">Welcome, {user?.name}!</h2>
          <p className="opacity-80 mt-2">Ready to level up your knowledge today?</p>
        </div>

        <div className="grid md:grid-cols-2 gap-8">
          {/* History */}
          <div className="space-y-4">
            <h3 className="text-lg font-semibold opacity-70 uppercase tracking-wider text-xs">Performance History</h3>
            {myHistory.length === 0 ? (
              <div className="q-card p-8 text-center opacity-50">No history found. Take your first test!</div>
            ) : myHistory.map(r => (
              <div key={r.id} className="q-card p-4 border-l-4 border-green-500 flex justify-between items-center">
                <div>
                  <p className="font-bold">{r.testTitle}</p>
                  <p className="text-xs opacity-50">{new Date(r.timestamp).toLocaleDateString()}</p>
                </div>
                <span className="text-xl font-black">{r.score}%</span>
              </div>
            ))}
          </div>

          {/* Open Tests */}
          <div className="space-y-4">
            <h3 className="text-lg font-semibold opacity-70 uppercase tracking-wider text-xs">Available Tests</h3>
            {availableTests.length === 0 ? (
              <p className="opacity-50 italic">No tests assigned yet.</p>
            ) : availableTests.map(t => (
              <div key={t.id} className="q-card p-6 flex flex-col gap-4">
                <div className="flex justify-between items-start">
                  <div>
                    <h4 className="font-bold text-lg">{t.title}</h4>
                    <p className="text-sm opacity-60">{t.questions.length} Questions | {t.timerMinutes} Minutes</p>
                  </div>
                </div>
                <button 
                  onClick={() => startTest(t)}
                  className="w-full py-3 bg-[var(--primary)] text-white rounded-xl font-bold hover:shadow-lg transition-all"
                >
                  Start Test
                </button>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  };

  const TestCreator = () => (
    <div className="max-w-2xl mx-auto py-8 animate-in slide-in-from-bottom-4">
      <h2 className="text-3xl font-bold mb-6">Create New Test</h2>
      <form onSubmit={createTest} className="q-card p-8 space-y-6">
        <div>
          <label className="block text-sm font-medium mb-1">Test Title</label>
          <input required name="title" className="w-full p-3 border rounded-lg bg-[var(--bg)] outline-none" placeholder="Biology Chapter 1: Cells" />
        </div>
        <div>
          <label className="block text-sm font-medium mb-1">Study Material (Text Source)</label>
          <textarea required name="text" className="w-full h-48 p-4 border rounded-lg bg-[var(--bg)] outline-none resize-none" placeholder="Paste textbook content here..." />
        </div>
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium mb-1">Question Count</label>
            <input required type="number" name="count" defaultValue={10} min={5} max={50} className="w-full p-3 border rounded-lg bg-[var(--bg)]" />
          </div>
          <div>
            <label className="block text-sm font-medium mb-1">Timer (Minutes)</label>
            <input required type="number" name="timer" defaultValue={15} min={1} max={120} className="w-full p-3 border rounded-lg bg-[var(--bg)]" />
          </div>
        </div>
        {error && <p className="text-red-500 text-sm">{error}</p>}
        <div className="flex gap-3 pt-4">
          <button type="button" onClick={() => setView('teacher-dash')} className="flex-1 py-3 font-medium">Cancel</button>
          <button disabled={isGenerating} type="submit" className="flex-2 py-3 bg-[var(--primary)] text-white rounded-lg font-bold px-8 disabled:opacity-50">
            {isGenerating ? 'AI Generating...' : 'Generate Test'}
          </button>
        </div>
      </form>
    </div>
  );

  const TestTaking = () => {
    if (!activeTest) return null;
    return (
      <div className="pb-32">
        <header className="sticky top-0 bg-[var(--card)] p-4 shadow-sm z-50 flex justify-between items-center mb-8 rounded-b-xl border">
          <div>
            <h3 className="font-bold text-lg">{activeTest.title}</h3>
            <p className="text-xs opacity-60">Progress: {Object.keys(answers).length}/{activeTest.questions.length}</p>
          </div>
          <div className={`px-4 py-2 rounded-lg font-mono font-bold ${timeLeft < 60 ? 'bg-red-500 text-white animate-pulse' : 'bg-gray-100 dark:bg-gray-800'}`}>
            {formatTime(timeLeft)}
          </div>
        </header>

        <div className="space-y-6">
          {activeTest.questions.map((q, idx) => (
            <div key={q.id} className="q-card p-6">
              <p className="font-bold mb-4">{idx + 1}. {q.text}</p>
              <div className="grid gap-2">
                {q.options.map(opt => (
                  <label key={opt.label} className={`flex items-center p-3 rounded-lg border cursor-pointer transition-colors ${answers[q.id] === opt.label ? 'border-blue-500 bg-blue-50 dark:bg-blue-900/20' : 'hover:bg-gray-50 dark:hover:bg-gray-800'}`}>
                    <input 
                      type="radio" 
                      name={q.id} 
                      className="hidden" 
                      onChange={() => setAnswers(prev => ({...prev, [q.id]: opt.label}))}
                    />
                    <span className="w-6 h-6 rounded-full border mr-3 flex items-center justify-center text-xs font-bold">
                      {answers[q.id] === opt.label ? '✓' : opt.label}
                    </span>
                    {opt.text}
                  </label>
                ))}
              </div>
            </div>
          ))}
        </div>

        <div className="fixed bottom-0 left-0 right-0 p-4 bg-[var(--bg)] border-t z-50 shadow-2xl">
          <div className="max-w-3xl mx-auto flex gap-4">
            <button onClick={handleTestSubmit} className="w-full py-4 bg-[var(--primary)] text-white rounded-2xl font-bold shadow-lg">Submit Test Now</button>
          </div>
        </div>
      </div>
    );
  };

  const ResultView = () => {
    const latest = results[0];
    if (!latest) return null;

    return (
      <div className="max-w-2xl mx-auto py-12 animate-in zoom-in-95">
        <div className="q-card p-12 text-center space-y-6">
          <div className="inline-block p-8 rounded-full bg-blue-50 dark:bg-blue-900/30 text-[var(--primary)]">
             <span className="text-6xl font-black">{latest.score}%</span>
          </div>
          <h2 className="text-3xl font-bold">Excellent Effort, {user?.name}!</h2>
          <p className="opacity-70">You completed <b>{latest.testTitle}</b>. Your result has been saved to your academic record.</p>

          <div className="bg-indigo-50 dark:bg-indigo-900/20 p-6 rounded-2xl text-left border border-indigo-100 dark:border-indigo-800">
            <h4 className="font-bold text-indigo-700 dark:text-indigo-300 flex items-center gap-2 mb-2">
              <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path d="M10 2a8 8 0 100 16 8 8 0 000-16zm1 11H9v-2h2v2zm0-4H9V5h2v4z" /></svg>
              AI Study Assistant Advice:
            </h4>
            <div className="text-sm space-y-2 opacity-90 leading-relaxed whitespace-pre-line">
              {aiAnalysis || "Analyzing your performance..."}
            </div>
          </div>

          <div className="flex gap-3 pt-6">
            <button onClick={() => setView('student-dash')} className="flex-1 py-3 font-bold border rounded-xl">Back to Dashboard</button>
            <button onClick={() => window.location.reload()} className="flex-1 py-3 bg-[var(--primary)] text-white rounded-xl font-bold">Sign Out</button>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-[var(--bg)] text-[var(--text)] selection:bg-blue-100">
      {/* Universal Nav */}
      <nav className="max-w-6xl mx-auto p-4 flex justify-between items-center">
        <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('home')}>
          <div className="w-8 h-8 bg-[var(--primary)] rounded-lg flex items-center justify-center text-white font-black">Q</div>
          <span className="font-bold text-xl tracking-tighter">QuickStudy</span>
        </div>
        <div className="flex items-center gap-4">
          {user && (
            <div className="text-right hidden sm:block">
              <p className="text-xs font-bold leading-none">{user.name}</p>
              <p className="text-[10px] opacity-50 uppercase tracking-tighter">{user.role}</p>
            </div>
          )}
          <button onClick={toggleTheme} className="p-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors">
            {theme === Theme.LIGHT ? '🌙' : '☀️'}
          </button>
        </div>
      </nav>

      <main className="max-w-6xl mx-auto p-4 min-h-[85vh]">
        {view === 'home' && <Home />}
        {view === 'login' && <Login />}
        {view === 'teacher-dash' && <TeacherDash />}
        {view === 'student-dash' && <StudentDash />}
        {view === 'test-creator' && <TestCreator />}
        {view === 'test-taking' && <TestTaking />}
        {view === 'result-view' && <ResultView />}
      </main>

      <footer className="text-center py-8 text-xs opacity-30">
        &copy; 2025 QuickStudy Learning Systems. Powered by Gemini AI.
      </footer>
    </div>
  );
};

export default App;

export interface Question {
  id: string;
  text: string;
  options: {
    label: string;
    text: string;
  }[];
  correctAnswer: string;
}

export interface Test {
  id: string;
  title: string;
  questions: Question[];
  createdAt: number;
  lastModified?: number;
  timerMinutes: number;
  creatorId: string;
}

export interface TestResult {
  id: string;
  testId: string;
  testTitle: string;
  studentId: string;
  studentName: string;
  score: number;
  totalQuestions: number;
  correctCount: number;
  timestamp: number;
  userAnswers: Record<string, string>; // Maps questionId to label
  aiFeedback?: string;
}

export interface User {
  id: string;
  name: string;
  role: 'teacher' | 'student';
  password?: string;
}

export enum Theme {
  LIGHT = 'light',
  DARK = 'dark'
}

export type ViewState = 'home' | 'login' | 'teacher-dash' | 'student-dash' | 'test-creator' | 'test-taking' | 'result-view' | 'review-detail';

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Question, Theme, ViewState, User, Test, TestResult } from './types';
import { generateQuestionsWithGemini, getAIStudyFeedback } from './services/geminiService';

const App: React.FC = () => {
  // Navigation & Auth
  const [view, setView] = useState<ViewState>('home');
  const [role, setRole] = useState<'teacher' | 'student' | null>(null);
  const [user, setUser] = useState<User | null>(null);
  const [theme, setTheme] = useState<Theme>(Theme.LIGHT);

  // Data Persistence
  const [tests, setTests] = useState<Test[]>([]);
  const [results, setResults] = useState<TestResult[]>([]);

  // Workflow State
  const [activeTest, setActiveTest] = useState<Test | null>(null);
  const [activeResult, setActiveResult] = useState<TestResult | null>(null);
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [timeLeft, setTimeLeft] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [editTestId, setEditTestId] = useState<string | null>(null);

  const timerRef = useRef<number | null>(null);

  // Initialize Data
  useEffect(() => {
    const savedTests = localStorage.getItem('qs_tests');
    const savedResults = localStorage.getItem('qs_results');
    const savedTheme = localStorage.getItem('theme') as Theme;

    if (savedTests) setTests(JSON.parse(savedTests));
    if (savedResults) setResults(JSON.parse(savedResults));
    if (savedTheme) {
      setTheme(savedTheme);
      document.documentElement.classList.toggle('dark', savedTheme === Theme.DARK);
    }
  }, []);

  useEffect(() => localStorage.setItem('qs_tests', JSON.stringify(tests)), [tests]);
  useEffect(() => localStorage.setItem('qs_results', JSON.stringify(results)), [results]);

  // Timer logic
  useEffect(() => {
    if (view === 'test-taking' && timeLeft > 0) {
      timerRef.current = window.setInterval(() => {
        setTimeLeft(prev => {
          if (prev <= 1) { handleTestSubmit(); return 0; }
          return prev - 1;
        });
      }, 1000);
    } else if (timerRef.current) {
      clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [view, timeLeft]);

  // --- Helpers ---

  const groupedResults = useMemo(() => {
    const groups: Record<string, TestResult[]> = {};
    results.forEach(res => {
      const date = new Date(res.timestamp).toLocaleDateString(undefined, { dateStyle: 'long' });
      if (!groups[date]) groups[date] = [];
      groups[date].push(res);
    });
    return Object.entries(groups).sort((a, b) => new Date(b[0]).getTime() - new Date(a[0]).getTime());
  }, [results]);

  const toggleTheme = () => {
    const newTheme = theme === Theme.LIGHT ? Theme.DARK : Theme.LIGHT;
    setTheme(newTheme);
    localStorage.setItem('theme', newTheme);
    document.documentElement.classList.toggle('dark', newTheme === Theme.DARK);
  };

  // --- Handlers ---

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const name = formData.get('name') as string;
    const id = formData.get('id') as string;
    const password = formData.get('password') as string;

    if (role === 'teacher' && password !== '1996') {
      setError('Incorrect Teacher Password.');
      return;
    }

    setUser({ id, name, role: role! });
    setError(null);
    setView(role === 'teacher' ? 'teacher-dash' : 'student-dash');
  };

  const handleSaveTest = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const text = formData.get('text') as string;
    const count = Number(formData.get('count'));
    const time = Number(formData.get('timer'));
    const title = formData.get('title') as string;

    setIsGenerating(true);
    setError(null);

    try {
      if (editTestId) {
        // Edit existing
        setTests(prev => prev.map(t => t.id === editTestId ? { 
          ...t, 
          title, 
          timerMinutes: time, 
          lastModified: Date.now() 
        } : t));
        setEditTestId(null);
        setView('teacher-dash');
      } else {
        // Generate new
        const qs = await generateQuestionsWithGemini(text, count);
        const newTest: Test = {
          id: `t-${Date.now()}`,
          title,
          questions: qs,
          createdAt: Date.now(),
          timerMinutes: time,
          creatorId: user!.id
        };
        setTests([newTest, ...tests]);
        setView('teacher-dash');
      }
    } catch (err) {
      setError('Operation failed.');
    } finally {
      setIsGenerating(false);
    }
  };

  const deleteTest = (id: string) => {
    if (confirm('Are you sure you want to delete this test? History will remain.')) {
      setTests(tests.filter(t => t.id !== id));
    }
  };

  const startTest = (test: Test) => {
    setActiveTest(test);
    setAnswers({});
    setTimeLeft(test.timerMinutes * 60);
    setView('test-taking');
  };

  const handleTestSubmit = async () => {
    if (!activeTest) return;

    let correct = 0;
    activeTest.questions.forEach(q => {
      if (answers[q.id] === q.correctAnswer) correct++;
    });

    const score = Math.round((correct / activeTest.questions.length) * 100);
    const feedback = await getAIStudyFeedback(score, activeTest.questions.filter(q => answers[q.id] !== q.correctAnswer).map(q => q.text).slice(0,3));

    const result: TestResult = {
      id: `r-${Date.now()}`,
      testId: activeTest.id,
      testTitle: activeTest.title,
      studentId: user!.id,
      studentName: user!.name,
      score,
      totalQuestions: activeTest.questions.length,
      correctCount: correct,
      timestamp: Date.now(),
      userAnswers: { ...answers },
      aiFeedback: feedback
    };

    setResults([result, ...results]);
    setActiveResult(result);
    setView('result-view');
  };

  const getScoreColor = (score: number) => {
    if (score >= 80) return 'text-green-500 bg-green-50 dark:bg-green-900/20';
    if (score >= 50) return 'text-yellow-600 bg-yellow-50 dark:bg-yellow-900/20';
    return 'text-red-500 bg-red-50 dark:bg-red-900/20';
  };

  // --- Components ---

  const QuestionLayout = ({ question, index, selected, onSelect, isReview = false, correctAnswer = '' }: any) => (
    <div className="q-card p-5 mb-4 border-none shadow-sm overflow-hidden">
      <div className="flex gap-4">
        <span className="flex-shrink-0 w-8 h-8 rounded-full bg-blue-100 dark:bg-blue-900/40 text-blue-600 flex items-center justify-center font-bold text-sm">
          {index + 1}
        </span>
        <div className="flex-grow">
          <p className="text-lg font-medium mb-4 leading-snug">{question.text}</p>
          <div className="grid sm:grid-cols-2 gap-3">
            {question.options.map((opt: any) => {
              const isUserChoice = selected === opt.label;
              const isCorrect = opt.label === correctAnswer;

              let style = "border-gray-100 dark:border-gray-800 hover:bg-gray-50 dark:hover:bg-gray-800";
              if (isReview) {
                if (isCorrect) style = "bg-green-100 border-green-500 dark:bg-green-900/30 text-green-700 dark:text-green-300";
                else if (isUserChoice && !isCorrect) style = "bg-red-100 border-red-500 dark:bg-red-900/30 text-red-700 dark:text-red-300";
              } else if (isUserChoice) {
                style = "border-blue-500 bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-300 ring-2 ring-blue-500/20";
              }

              return (
                <button
                  key={opt.label}
                  disabled={isReview}
                  onClick={() => onSelect(opt.label)}
                  className={`flex items-start gap-3 p-3 text-left border rounded-xl transition-all duration-200 ${style}`}
                >
                  <span className="font-black text-xs opacity-40 mt-0.5">{opt.label}.</span>
                  <span className="text-sm font-medium">{opt.text}</span>
                </button>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );

  const ReviewDetailModal = () => {
    if (!activeResult) return null;
    const test = tests.find(t => t.id === activeResult.testId) || { questions: [] };

    return (
      <div className="animate-in fade-in zoom-in-95 max-w-4xl mx-auto py-6">
        <button onClick={() => setView(user?.role === 'teacher' ? 'teacher-dash' : 'student-dash')} className="mb-4 text-blue-500 font-bold flex items-center gap-1">
          ← Back to Dashboard
        </button>
        <div className="q-card p-6 mb-6">
          <div className="flex justify-between items-end">
            <div>
              <h2 className="text-2xl font-bold">{activeResult.studentName}'s Performance</h2>
              <p className="opacity-60 text-sm">{activeResult.testTitle} • {new Date(activeResult.timestamp).toLocaleString()}</p>
            </div>
            <div className={`px-4 py-2 rounded-xl font-black text-2xl ${getScoreColor(activeResult.score)}`}>
              {activeResult.score}%
            </div>
          </div>
        </div>
        <div className="space-y-4">
          {test.questions.map((q, i) => (
            <QuestionLayout 
              key={q.id} 
              question={q} 
              index={i} 
              selected={activeResult.userAnswers[q.id]} 
              isReview={true} 
              correctAnswer={q.correctAnswer} 
            />
          ))}
        </div>
      </div>
    );
  };

  const TeacherDash = () => (
    <div className="space-y-10 animate-in fade-in">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-black tracking-tight">Management Console</h2>
          <p className="opacity-50 text-sm">Create, edit and track exams</p>
        </div>
        <button onClick={() => { setEditTestId(null); setView('test-creator'); }} className="px-6 py-3 bg-[var(--primary)] text-white rounded-2xl font-bold shadow-lg shadow-blue-500/20 hover:scale-105 transition-transform">+ New Test</button>
      </div>

      <div className="grid lg:grid-cols-3 gap-8">
        <div className="lg:col-span-1 space-y-4">
          <h3 className="text-xs font-black uppercase tracking-widest opacity-40">Active Exams</h3>
          {tests.length === 0 ? <p className="opacity-30 italic text-sm py-8 border-2 border-dashed rounded-2xl text-center">Empty Repository</p> : tests.map(t => (
            <div key={t.id} className="q-card p-5 group">
              <div className="flex justify-between items-start mb-3">
                <h4 className="font-bold">{t.title}</h4>
                <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => { setEditTestId(t.id); setView('test-creator'); }} title="Edit" className="p-2 hover:bg-blue-50 dark:hover:bg-blue-900/30 rounded-lg text-blue-500">✎</button>
                  <button onClick={() => deleteTest(t.id)} title="Delete" className="p-2 hover:bg-red-50 dark:hover:bg-red-900/30 rounded-lg text-red-500">✕</button>
                </div>
              </div>
              <div className="flex justify-between items-center text-xs">
                <span className="opacity-50">{t.questions.length} Questions • {t.timerMinutes}m</span>
                <button onClick={() => { setActiveTest(t); setView('test-taking'); }} className="text-blue-500 font-bold hover:underline">Preview Exam</button>
              </div>
            </div>
          ))}
        </div>

        <div className="lg:col-span-2 space-y-6">
          <h3 className="text-xs font-black uppercase tracking-widest opacity-40">Historical Attendee Grouping</h3>
          <div className="space-y-8">
            {groupedResults.length === 0 ? <p className="opacity-30 italic py-10 text-center">No student data yet.</p> : groupedResults.map(([date, items]) => (
              <section key={date}>
                <div className="sticky top-0 bg-[var(--bg)] py-2 z-10">
                  <h4 className="text-sm font-bold text-blue-600 dark:text-blue-400 flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full bg-blue-500"></span>
                    {date}
                    <span className="ml-auto text-[10px] bg-blue-100 dark:bg-blue-900/40 px-2 py-0.5 rounded-full">{items.length} Students</span>
                  </h4>
                </div>
                <div className="mt-4 grid gap-3">
                  {items.map(r => (
                    <div 
                      key={r.id} 
                      onClick={() => { setActiveResult(r); setView('review-detail'); }}
                      className="q-card p-4 flex items-center justify-between cursor-pointer hover:border-blue-500/30 transition-all border-l-4 border-l-blue-500"
                    >
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 rounded-xl bg-gray-100 dark:bg-gray-800 flex items-center justify-center font-black text-sm uppercase">
                          {r.studentName.charAt(0)}
                        </div>
                        <div>
                          <p className="font-bold text-sm leading-none">{r.studentName}</p>
                          <p className="text-[10px] opacity-50 mt-1 uppercase tracking-tighter">{r.testTitle} • {new Date(r.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
                        </div>
                      </div>
                      <div className={`px-3 py-1 rounded-lg text-xs font-black ${getScoreColor(r.score)}`}>
                        {r.correctCount}/{r.totalQuestions} ({r.score}%)
                      </div>
                    </div>
                  ))}
                </div>
              </section>
            ))}
          </div>
        </div>
      </div>
    </div>
  );

  const StudentDash = () => (
    <div className="space-y-8 animate-in fade-in">
      <div className="bg-gradient-to-br from-indigo-600 to-blue-700 p-10 rounded-[2.5rem] text-white shadow-2xl shadow-blue-500/20">
        <h2 className="text-4xl font-black mb-2">Hello, {user?.name.split(' ')[0]}!</h2>
        <p className="opacity-80 font-medium">Your learning journey continues. Choose a test below to start.</p>
      </div>

      <div className="grid md:grid-cols-2 gap-10">
        <section>
          <h3 className="text-xs font-black uppercase tracking-widest opacity-40 mb-6">Your History</h3>
          <div className="space-y-3">
            {results.filter(r => r.studentId === user?.id).map(r => (
              <div 
                key={r.id} 
                onClick={() => { setActiveResult(r); setView('review-detail'); }}
                className="q-card p-5 flex justify-between items-center cursor-pointer border-l-4 border-l-green-500 hover:scale-[1.01] transition-transform"
              >
                <div>
                  <h4 className="font-bold">{r.testTitle}</h4>
                  <p className="text-[10px] opacity-50">{new Date(r.timestamp).toLocaleString()}</p>
                </div>
                <div className={`px-3 py-1 rounded-lg font-black ${getScoreColor(r.score)}`}>
                  {r.score}%
                </div>
              </div>
            ))}
          </div>
        </section>

        <section>
          <h3 className="text-xs font-black uppercase tracking-widest opacity-40 mb-6">Open Exams</h3>
          <div className="grid gap-4">
            {tests.map(t => (
              <div key={t.id} className="q-card p-6 flex flex-col items-center text-center gap-4">
                <div>
                  <h4 className="text-xl font-bold">{t.title}</h4>
                  <p className="text-sm opacity-50 mt-1">{t.questions.length} questions • {t.timerMinutes} mins</p>
                </div>
                <button onClick={() => startTest(t)} className="w-full py-3 bg-[var(--primary)] text-white rounded-2xl font-bold shadow-lg shadow-blue-500/20">Take Exam</button>
              </div>
            ))}
          </div>
        </section>
      </div>
    </div>
  );

  // --- Main Render ---

  return (
    <div className="min-h-screen pb-20">
      <nav className="max-w-6xl mx-auto p-6 flex justify-between items-center">
        <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('home')}>
          <div className="w-10 h-10 bg-[var(--primary)] rounded-xl flex items-center justify-center text-white font-black shadow-lg shadow-blue-500/20">Q</div>
          <span className="font-black text-2xl tracking-tighter">QuickStudy</span>
        </div>
        <div className="flex items-center gap-4">
          {user && (
            <div className="text-right hidden sm:block mr-2">
              <p className="text-sm font-black leading-none">{user.name}</p>
              <p className="text-[10px] opacity-40 uppercase font-bold tracking-widest">{user.role}</p>
            </div>
          )}
          <button onClick={toggleTheme} className="w-10 h-10 rounded-xl bg-[var(--card)] shadow-sm flex items-center justify-center border">
            {theme === Theme.LIGHT ? '🌙' : '☀️'}
          </button>
          {user && <button onClick={() => window.location.reload()} className="text-xs font-bold opacity-40 hover:opacity-100">Logout</button>}
        </div>
      </nav>

      <main className="max-w-6xl mx-auto px-4 mt-6">
        {view === 'home' && (
          <div className="flex flex-col items-center justify-center min-h-[70vh] text-center space-y-12">
            <div className="space-y-6">
              <h1 className="text-7xl font-black tracking-tight leading-none bg-gradient-to-b from-[var(--text)] to-[var(--text)] opacity-90 bg-clip-text text-transparent">
                Adaptive Assessment.<br/><span className="text-blue-600">Perfect Results.</span>
              </h1>
              <p className="text-lg opacity-60 max-w-lg mx-auto font-medium">
                The world's first AI-powered LMS for rapid assessment and detailed performance tracking.
              </p>
            </div>
            <div className="flex gap-4 w-full max-w-lg">
              <button onClick={() => { setRole('teacher'); setView('login'); }} className="flex-1 h-16 bg-blue-600 text-white rounded-[1.25rem] font-black text-lg shadow-2xl shadow-blue-600/30 hover:scale-105 transition-all">Teacher Login</button>
              <button onClick={() => { setRole('student'); setView('login'); }} className="flex-1 h-16 bg-[var(--card)] border-2 rounded-[1.25rem] font-black text-lg hover:scale-105 transition-all">Student Portal</button>
            </div>
          </div>
        )}

        {view === 'login' && (
          <div className="max-w-md mx-auto py-12">
            <div className="q-card p-10">
              <h2 className="text-3xl font-black mb-2 leading-none">{role === 'teacher' ? 'Admin Access' : 'Student Access'}</h2>
              <p className="text-sm opacity-50 mb-8 font-medium">Please enter your credentials to continue</p>
              <form onSubmit={handleLogin} className="space-y-5">
                <input required name="name" type="text" className="w-full h-14 px-5 rounded-2xl bg-gray-50 dark:bg-gray-800 border outline-none focus:border-blue-500 font-medium" placeholder="Full Name" />
                <input required name="id" type="text" className="w-full h-14 px-5 rounded-2xl bg-gray-50 dark:bg-gray-800 border outline-none focus:border-blue-500 font-medium" placeholder="ID Number" />
                {role === 'teacher' && <input required name="password" type="password" className="w-full h-14 px-5 rounded-2xl bg-gray-50 dark:bg-gray-800 border outline-none focus:border-blue-500 font-medium" placeholder="Security Passphrase" />}
                {error && <p className="text-red-500 text-sm font-bold">{error}</p>}
                <button type="submit" className="w-full h-14 bg-blue-600 text-white rounded-2xl font-black text-lg shadow-lg">Authenticate</button>
                <button type="button" onClick={() => setView('home')} className="w-full text-center text-sm font-bold opacity-40">Cancel</button>
              </form>
            </div>
          </div>
        )}

        {view === 'teacher-dash' && <TeacherDash />}
        {view === 'student-dash' && <StudentDash />}
        {view === 'review-detail' && <ReviewDetailModal />}

        {view === 'test-creator' && (
          <div className="max-w-3xl mx-auto py-8">
            <h2 className="text-4xl font-black mb-8">{editTestId ? 'Edit Exam Settings' : 'Draft New Exam'}</h2>
            <form onSubmit={handleSaveTest} className="q-card p-10 space-y-8">
              <div className="space-y-2">
                <label className="text-sm font-black uppercase tracking-widest opacity-40">Test Information</label>
                <input required name="title" defaultValue={tests.find(t => t.id === editTestId)?.title} className="w-full h-14 px-5 rounded-2xl bg-gray-50 dark:bg-gray-800 border outline-none focus:border-blue-500 font-bold text-xl" placeholder="E.g. Midterm Physics 2025" />
              </div>

              {!editTestId && (
                <div className="space-y-2">
                  <label className="text-sm font-black uppercase tracking-widest opacity-40">Learning Material</label>
                  <textarea required name="text" className="w-full h-64 p-5 rounded-2xl bg-gray-50 dark:bg-gray-800 border outline-none focus:border-blue-500 resize-none font-medium leading-relaxed" placeholder="Paste your study content here... AI will generate questions based on this." />
                </div>
              )}

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-black uppercase tracking-widest opacity-40">Questions</label>
                  <input required type="number" name="count" defaultValue={10} min={5} max={50} disabled={!!editTestId} className="w-full h-14 px-5 rounded-2xl bg-gray-50 dark:bg-gray-800 border outline-none focus:border-blue-500 font-bold" />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-black uppercase tracking-widest opacity-40">Duration (Min)</label>
                  <input required type="number" name="timer" defaultValue={tests.find(t => t.id === editTestId)?.timerMinutes || 15} min={1} max={120} className="w-full h-14 px-5 rounded-2xl bg-gray-50 dark:bg-gray-800 border outline-none focus:border-blue-500 font-bold" />
                </div>
              </div>

              {error && <p className="text-red-500 font-bold">{error}</p>}

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setView('teacher-dash')} className="flex-1 font-bold h-14">Discard</button>
                <button disabled={isGenerating} type="submit" className="flex-[2] h-14 bg-blue-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-blue-500/20">
                  {isGenerating ? 'AI Working...' : editTestId ? 'Save Changes' : 'Generate & Publish'}
                </button>
              </div>
            </form>
          </div>
        )}

        {view === 'test-taking' && activeTest && (
          <div className="max-w-3xl mx-auto pb-32">
             <header className="sticky top-0 bg-[var(--bg)]/80 backdrop-blur-xl py-6 z-50 flex justify-between items-center mb-8 border-b">
                <div>
                  <h3 className="font-black text-2xl tracking-tight">{activeTest.title}</h3>
                  <p className="text-xs font-bold opacity-40 uppercase tracking-widest">Question {Object.keys(answers).length + 1} of {activeTest.questions.length}</p>
                </div>
                <div className={`px-6 py-3 rounded-2xl font-mono text-xl font-black ${timeLeft < 60 ? 'bg-red-500 text-white animate-pulse' : 'bg-[var(--card)] border shadow-sm'}`}>
                  {Math.floor(timeLeft / 60)}:{String(timeLeft % 60).padStart(2, '0')}
                </div>
             </header>
             <div className="space-y-6">
                {activeTest.questions.map((q, i) => (
                  <QuestionLayout 
                    key={q.id} 
                    question={q} 
                    index={i} 
                    selected={answers[q.id]} 
                    onSelect={(label: string) => setAnswers({...answers, [q.id]: label})} 
                  />
                ))}
             </div>
             <div className="fixed bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-[var(--bg)] to-transparent pointer-events-none">
                <div className="max-w-3xl mx-auto pointer-events-auto">
                  <button onClick={handleTestSubmit} className="w-full h-16 bg-blue-600 text-white rounded-[1.25rem] font-black text-xl shadow-2xl shadow-blue-600/40 transform hover:scale-[1.02] active:scale-95 transition-all">Submit Final Answers</button>
                </div>
             </div>
          </div>
        )}

        {view === 'result-view' && activeResult && (
          <div className="max-w-xl mx-auto py-20 text-center animate-in zoom-in-95">
             <div className="w-32 h-32 rounded-[2.5rem] bg-blue-600 text-white flex items-center justify-center text-4xl font-black mx-auto mb-8 shadow-2xl shadow-blue-600/30">
               {activeResult.score}%
             </div>
             <h2 className="text-4xl font-black tracking-tight mb-2">Well Done, {user?.name.split(' ')[0]}!</h2>
             <p className="opacity-50 font-medium mb-12">Your score has been successfully reported to the staff dashboard for review.</p>

             <div className="bg-blue-50 dark:bg-blue-900/20 p-8 rounded-3xl text-left border border-blue-100 dark:border-blue-800 mb-10">
               <h4 className="font-black text-blue-700 dark:text-blue-400 text-xs uppercase tracking-widest mb-4 flex items-center gap-2">
                 <span className="w-1.5 h-1.5 rounded-full bg-blue-500"></span>
                 AI Mentor Feedback
               </h4>
               <p className="text-sm font-medium leading-relaxed opacity-80 whitespace-pre-line">{activeResult.aiFeedback}</p>
             </div>

             <div className="flex flex-col gap-3">
               <button onClick={() => setView('review-detail')} className="w-full h-14 border-2 rounded-2xl font-black">Review My Answers</button>
               <button onClick={() => setView('student-dash')} className="w-full h-14 bg-gray-900 text-white dark:bg-white dark:text-gray-900 rounded-2xl font-black shadow-lg">Back to Home</button>
             </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

export interface Question {
  id: string;
  text: string;
  options: {
    label: string;
    text: string;
  }[];
  correctAnswer: string;
}

export interface Test {
  id: string;
  title: string;
  questions: Question[];
  createdAt: number;
  lastModified?: number;
  timerMinutes: number;
  creatorId: string;
}

export interface TestResult {
  id: string;
  testId: string;
  testTitle: string;
  studentId: string;
  studentName: string;
  score: number;
  totalQuestions: number;
  correctCount: number;
  timestamp: number;
  userAnswers: Record<string, string>; // Maps questionId to label
  questionsSnapshot: Question[]; // Snapshot of questions at time of test
  aiFeedback?: string;
}

export interface User {
  id: string;
  name: string;
  role: 'teacher' | 'student';
  password?: string;
}

export enum Theme {
  LIGHT = 'light',
  DARK = 'dark'
}

export type ViewState = 'home' | 'login' | 'teacher-dash' | 'student-dash' | 'test-creator' | 'test-taking' | 'result-view' | 'review-detail';

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Question, Theme, ViewState, User, Test, TestResult } from './types';
import { generateQuestionsWithGemini, getAIStudyFeedback } from './services/geminiService';

const App: React.FC = () => {
  // Navigation & Auth
  const [view, setView] = useState<ViewState>('home');
  const [role, setRole] = useState<'teacher' | 'student' | null>(null);
  const [user, setUser] = useState<User | null>(null);
  const [theme, setTheme] = useState<Theme>(Theme.LIGHT);

  // Data Persistence
  const [tests, setTests] = useState<Test[]>([]);
  const [results, setResults] = useState<TestResult[]>([]);

  // Workflow State
  const [activeTest, setActiveTest] = useState<Test | null>(null);
  const [activeResult, setActiveResult] = useState<TestResult | null>(null);
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [timeLeft, setTimeLeft] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [editTestId, setEditTestId] = useState<string | null>(null);
  const [isPreviewMode, setIsPreviewMode] = useState(false);

  const timerRef = useRef<number | null>(null);

  // Initialize Data
  useEffect(() => {
    const savedTests = localStorage.getItem('qs_tests');
    const savedResults = localStorage.getItem('qs_results');
    const savedTheme = localStorage.getItem('theme') as Theme;

    if (savedTests) setTests(JSON.parse(savedTests));
    if (savedResults) setResults(JSON.parse(savedResults));
    if (savedTheme) {
      setTheme(savedTheme);
      document.documentElement.classList.toggle('dark', savedTheme === Theme.DARK);
    }
  }, []);

  useEffect(() => localStorage.setItem('qs_tests', JSON.stringify(tests)), [tests]);
  useEffect(() => localStorage.setItem('qs_results', JSON.stringify(results)), [results]);

  // Timer logic
  useEffect(() => {
    if (view === 'test-taking' && !isPreviewMode && timeLeft > 0) {
      timerRef.current = window.setInterval(() => {
        setTimeLeft(prev => {
          if (prev <= 1) { handleTestSubmit(); return 0; }
          return prev - 1;
        });
      }, 1000);
    } else if (timerRef.current) {
      clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [view, timeLeft, isPreviewMode]);

  // --- Hierarchical Grouping Logic ---
  const groupedResults = useMemo(() => {
    // Group 1: Date (e.g. "March 4, 2025")
    const dateGroups: Record<string, Record<string, TestResult[]>> = {};

    results.forEach(res => {
      const dateKey = new Date(res.timestamp).toLocaleDateString(undefined, { dateStyle: 'long' });
      const testKey = res.testTitle;

      if (!dateGroups[dateKey]) dateGroups[dateKey] = {};
      if (!dateGroups[dateKey][testKey]) dateGroups[dateKey][testKey] = [];

      dateGroups[dateKey][testKey].push(res);
    });

    // Sort dates descending
    return Object.entries(dateGroups).sort((a, b) => new Date(b[0]).getTime() - new Date(a[0]).getTime());
  }, [results]);

  const toggleTheme = () => {
    const newTheme = theme === Theme.LIGHT ? Theme.DARK : Theme.LIGHT;
    setTheme(newTheme);
    localStorage.setItem('theme', newTheme);
    document.documentElement.classList.toggle('dark', newTheme === Theme.DARK);
  };

  // --- Handlers ---

  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const name = formData.get('name') as string;
    const id = formData.get('id') as string;
    const password = formData.get('password') as string;

    if (role === 'teacher' && password !== '1996') {
      setError('Incorrect Teacher Password.');
      return;
    }

    setUser({ id, name, role: role! });
    setError(null);
    setView(role === 'teacher' ? 'teacher-dash' : 'student-dash');
  };

  const handleSaveTest = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const text = formData.get('text') as string;
    const count = Number(formData.get('count'));
    const time = Number(formData.get('timer'));
    const title = formData.get('title') as string;

    setIsGenerating(true);
    setError(null);

    try {
      if (editTestId) {
        setTests(prev => prev.map(t => t.id === editTestId ? { 
          ...t, 
          title, 
          timerMinutes: time, 
          lastModified: Date.now() 
        } : t));
        setEditTestId(null);
        setView('teacher-dash');
      } else {
        const qs = await generateQuestionsWithGemini(text, count);
        const newTest: Test = {
          id: `t-${Date.now()}`,
          title,
          questions: qs,
          createdAt: Date.now(),
          timerMinutes: time,
          creatorId: user!.id
        };
        setTests([newTest, ...tests]);
        setView('teacher-dash');
      }
    } catch (err) {
      setError('Operation failed.');
    } finally {
      setIsGenerating(false);
    }
  };

  const deleteTest = (id: string) => {
    if (confirm('Are you sure you want to delete this test? Historical student results will be preserved.')) {
      setTests(tests.filter(t => t.id !== id));
    }
  };

  const startTest = (test: Test, preview: boolean = false) => {
    setActiveTest(test);
    setAnswers({});
    setIsPreviewMode(preview);
    setTimeLeft(test.timerMinutes * 60);
    setView('test-taking');
  };

  const handleTestSubmit = async () => {
    if (!activeTest || isPreviewMode) {
      setView('teacher-dash');
      return;
    }

    let correct = 0;
    activeTest.questions.forEach(q => {
      if (answers[q.id] === q.correctAnswer) correct++;
    });

    const score = Math.round((correct / activeTest.questions.length) * 100);
    const feedback = await getAIStudyFeedback(score, activeTest.questions.filter(q => answers[q.id] !== q.correctAnswer).map(q => q.text).slice(0,3));

    const result: TestResult = {
      id: `r-${Date.now()}`,
      testId: activeTest.id,
      testTitle: activeTest.title,
      studentId: user!.id,
      studentName: user!.name,
      score,
      totalQuestions: activeTest.questions.length,
      correctCount: correct,
      timestamp: Date.now(),
      userAnswers: { ...answers },
      questionsSnapshot: [...activeTest.questions], // Crucial: store snapshot
      aiFeedback: feedback
    };

    setResults([result, ...results]);
    setActiveResult(result);
    setView('result-view');
  };

  const getScoreColor = (score: number) => {
    if (score >= 80) return 'text-green-600 dark:text-green-400 bg-green-50 dark:bg-green-900/20';
    if (score >= 50) return 'text-yellow-600 dark:text-yellow-400 bg-yellow-50 dark:bg-yellow-900/20';
    return 'text-red-600 dark:text-red-400 bg-red-50 dark:bg-red-900/20';
  };

  // --- Simplified Question UI ---
  const QuestionLayout = ({ question, index, selected, onSelect, isReview = false, correctAnswer = '' }: any) => (
    <div className="q-card p-6 mb-4 border border-slate-200 dark:border-slate-800 shadow-none">
      <div className="flex gap-4">
        <span className="flex-shrink-0 w-8 h-8 rounded-lg bg-blue-100 dark:bg-blue-900/40 text-blue-600 dark:text-blue-400 flex items-center justify-center font-bold text-sm">
          {index + 1}
        </span>
        <div className="flex-grow">
          <p className="text-lg font-semibold mb-4 text-high-contrast leading-relaxed">{question.text}</p>
          <div className="grid gap-2">
            {question.options.map((opt: any) => {
              const isUserChoice = selected === opt.label;
              const isCorrect = opt.label === correctAnswer;

              let style = "border-slate-100 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800/50";
              if (isReview) {
                if (isCorrect) style = "bg-green-100 dark:bg-green-900/30 border-green-500 text-green-700 dark:text-green-300 font-bold";
                else if (isUserChoice && !isCorrect) style = "bg-red-100 dark:bg-red-900/30 border-red-500 text-red-700 dark:text-red-300";
              } else if (isUserChoice) {
                style = "border-blue-500 bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-300 ring-2 ring-blue-500/20";
              }

              return (
                <button
                  key={opt.label}
                  disabled={isReview}
                  onClick={() => onSelect(opt.label)}
                  className={`flex items-center gap-4 p-3.5 text-left border rounded-xl transition-all duration-200 ${style}`}
                >
                  <span className={`w-7 h-7 flex items-center justify-center rounded-md border text-xs font-black ${isUserChoice ? 'bg-blue-600 text-white' : 'opacity-40'}`}>
                    {opt.label}
                  </span>
                  <span className="text-[15px] font-medium leading-tight">{opt.text}</span>
                </button>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );

  const ReviewDetailModal = () => {
    if (!activeResult) return null;

    return (
      <div className="animate-in max-w-4xl mx-auto py-6">
        <button onClick={() => setView(user?.role === 'teacher' ? 'teacher-dash' : 'student-dash')} className="mb-6 text-blue-500 font-bold flex items-center gap-2 hover:translate-x-[-4px] transition-transform">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
          Back to Results
        </button>
        <div className="q-card p-8 mb-8">
          <div className="flex justify-between items-start">
            <div className="space-y-1">
              <h2 className="text-2xl font-black text-high-contrast">{activeResult.studentName}</h2>
              <p className="text-low-contrast font-medium">{activeResult.testTitle}</p>
              <p className="text-xs text-low-contrast opacity-70">Attempted: {new Date(activeResult.timestamp).toLocaleString()}</p>
            </div>
            <div className={`px-6 py-3 rounded-2xl text-center shadow-sm ${getScoreColor(activeResult.score)}`}>
              <p className="text-xs font-black uppercase tracking-widest opacity-60">Result</p>
              <p className="text-3xl font-black">{activeResult.correctCount}/{activeResult.totalQuestions}</p>
              <p className="text-sm font-bold opacity-80">{activeResult.score}%</p>
            </div>
          </div>
        </div>
        <div className="space-y-4">
          {activeResult.questionsSnapshot.map((q, i) => (
            <QuestionLayout 
              key={q.id} 
              question={q} 
              index={i} 
              selected={activeResult.userAnswers[q.id]} 
              isReview={true} 
              correctAnswer={q.correctAnswer} 
            />
          ))}
        </div>
      </div>
    );
  };

  const TeacherDash = () => (
    <div className="space-y-12 animate-in">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-4xl font-black tracking-tight text-high-contrast">Dashboard</h2>
          <p className="text-low-contrast font-medium">Manage your institution's exams and student data.</p>
        </div>
        <button onClick={() => { setEditTestId(null); setView('test-creator'); }} className="px-8 py-4 bg-[var(--primary)] text-white rounded-2xl font-black shadow-xl shadow-blue-500/30 hover:scale-105 transition-transform">Create Test</button>
      </div>

      <div className="grid lg:grid-cols-12 gap-10">
        {/* Exams List */}
        <div className="lg:col-span-4 space-y-6">
          <div className="flex items-center gap-2 mb-4">
            <h3 className="text-xs font-black uppercase tracking-[0.2em] text-low-contrast">Exam Repository</h3>
            <span className="flex-grow border-t dark:border-slate-800"></span>
          </div>
          {tests.length === 0 ? (
            <div className="p-12 text-center border-2 border-dashed rounded-3xl opacity-30">
              <p className="font-bold">No exams published</p>
            </div>
          ) : tests.map(t => (
            <div key={t.id} className="q-card p-6 group relative">
              <div className="flex justify-between items-start mb-4">
                <div className="space-y-1">
                  <h4 className="font-black text-lg text-high-contrast leading-tight">{t.title}</h4>
                  <p className="text-xs font-bold text-low-contrast uppercase tracking-tighter">{t.questions.length} Items • {t.timerMinutes}m</p>
                </div>
              </div>
              <div className="flex gap-2">
                <button onClick={() => { startTest(t, true); }} className="flex-1 py-2 bg-slate-100 dark:bg-slate-800 rounded-lg text-xs font-black hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors">View Content</button>
                <button onClick={() => { setEditTestId(t.id); setView('test-creator'); }} className="p-2 border rounded-lg hover:bg-blue-50 dark:hover:bg-blue-900/20 text-blue-500">✎</button>
                <button onClick={() => deleteTest(t.id)} className="p-2 border rounded-lg hover:bg-red-50 dark:hover:bg-red-900/20 text-red-500">✕</button>
              </div>
            </div>
          ))}
        </div>

        {/* Grouped Results */}
        <div className="lg:col-span-8 space-y-8">
          <div className="flex items-center gap-2 mb-4">
            <h3 className="text-xs font-black uppercase tracking-[0.2em] text-low-contrast">Attendance & Performance</h3>
            <span className="flex-grow border-t dark:border-slate-800"></span>
          </div>

          {groupedResults.length === 0 ? (
            <div className="p-20 text-center opacity-30">
              <p className="text-2xl font-black">No submissions yet.</p>
              <p className="font-medium mt-2">Waiting for students to complete exams.</p>
            </div>
          ) : groupedResults.map(([date, testsInDate]) => (
            <div key={date} className="space-y-6">
              <div className="flex items-center gap-4">
                <div className="h-px flex-grow bg-slate-200 dark:bg-slate-800"></div>
                <h4 className="text-sm font-black text-blue-600 dark:text-blue-400 px-4 py-1.5 bg-blue-50 dark:bg-blue-900/20 rounded-full">{date}</h4>
                <div className="h-px flex-grow bg-slate-200 dark:bg-slate-800"></div>
              </div>

              {Object.entries(testsInDate).map(([testTitle, studentResults]) => (
                <div key={testTitle} className="space-y-3">
                  <div className="flex items-center justify-between px-2">
                    <h5 className="font-bold text-high-contrast flex items-center gap-2">
                      <span className="w-1.5 h-1.5 rounded-full bg-slate-400"></span>
                      {testTitle}
                    </h5>
                    <span className="text-[10px] font-black uppercase text-low-contrast">{studentResults.length} Attendees</span>
                  </div>
                  <div className="grid sm:grid-cols-2 gap-3">
                    {studentResults.map(r => (
                      <div 
                        key={r.id} 
                        onClick={() => { setActiveResult(r); setView('review-detail'); }}
                        className="q-card p-4 flex items-center justify-between cursor-pointer hover:border-blue-500/50 transition-all border-l-4 border-l-blue-500"
                      >
                        <div className="flex items-center gap-3">
                          <div className="w-9 h-9 rounded-lg bg-slate-100 dark:bg-slate-800 flex items-center justify-center font-black text-xs">
                            {r.studentName.charAt(0)}
                          </div>
                          <div>
                            <p className="font-bold text-sm text-high-contrast leading-none">{r.studentName}</p>
                            <p className="text-[10px] font-medium text-low-contrast mt-1">{new Date(r.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</p>
                          </div>
                        </div>
                        <div className={`px-2.5 py-1 rounded-lg text-[11px] font-black whitespace-nowrap shadow-sm ${getScoreColor(r.score)}`}>
                          {r.correctCount}/{r.totalQuestions} • {r.score}%
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          ))}
        </div>
      </div>
    </div>
  );

  const StudentDash = () => (
    <div className="space-y-12 animate-in">
      <div className="bg-gradient-to-br from-blue-700 via-blue-600 to-indigo-700 p-12 rounded-[2.5rem] text-white shadow-2xl shadow-blue-500/20 relative overflow-hidden">
        <div className="absolute top-[-20%] right-[-10%] w-64 h-64 bg-white/10 rounded-full blur-3xl"></div>
        <div className="relative z-10">
          <h2 className="text-5xl font-black mb-3 tracking-tight">Welcome, {user?.name.split(' ')[0]}</h2>
          <p className="text-xl font-medium opacity-80">Track your progress and take your scheduled exams.</p>
        </div>
      </div>

      <div className="grid md:grid-cols-12 gap-10">
        <section className="md:col-span-5 space-y-6">
          <h3 className="text-xs font-black uppercase tracking-[0.2em] text-low-contrast">Performance Archive</h3>
          <div className="space-y-3">
            {results.filter(r => r.studentId === user?.id).map(r => (
              <div 
                key={r.id} 
                onClick={() => { setActiveResult(r); setView('review-detail'); }}
                className="q-card p-5 flex justify-between items-center cursor-pointer border-l-4 border-l-green-500 hover:translate-x-1 transition-transform"
              >
                <div>
                  <h4 className="font-bold text-high-contrast">{r.testTitle}</h4>
                  <p className="text-[10px] font-bold text-low-contrast uppercase tracking-tighter mt-1">{new Date(r.timestamp).toLocaleDateString()} @ {new Date(r.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</p>
                </div>
                <div className={`px-4 py-1.5 rounded-xl font-black text-sm ${getScoreColor(r.score)}`}>
                  {r.score}%
                </div>
              </div>
            ))}
            {results.filter(r => r.studentId === user?.id).length === 0 && <p className="text-center py-10 opacity-30 italic">No exams completed yet.</p>}
          </div>
        </section>

        <section className="md:col-span-7 space-y-6">
          <h3 className="text-xs font-black uppercase tracking-[0.2em] text-low-contrast">Assigned Tests</h3>
          <div className="grid gap-5">
            {tests.map(t => (
              <div key={t.id} className="q-card p-8 flex flex-col md:flex-row items-center justify-between gap-6 group">
                <div className="text-center md:text-left">
                  <h4 className="text-2xl font-black text-high-contrast tracking-tight mb-1">{t.title}</h4>
                  <p className="text-sm font-bold text-low-contrast uppercase tracking-widest">{t.questions.length} Questions • {t.timerMinutes} Minutes</p>
                </div>
                <button onClick={() => startTest(t)} className="w-full md:w-auto px-10 py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg shadow-blue-500/20 group-hover:scale-105 transition-transform">Begin Now</button>
              </div>
            ))}
            {tests.length === 0 && <p className="text-center py-10 opacity-30 italic">No tests are currently assigned to you.</p>}
          </div>
        </section>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen pb-20">
      <nav className="max-w-6xl mx-auto px-6 py-8 flex justify-between items-center">
        <div className="flex items-center gap-3 cursor-pointer group" onClick={() => setView('home')}>
          <div className="w-11 h-11 bg-[var(--primary)] rounded-[0.8rem] flex items-center justify-center text-white font-black shadow-xl shadow-blue-500/20 group-hover:rotate-6 transition-transform">Q</div>
          <span className="font-black text-2xl tracking-tighter text-high-contrast">QuickStudy <span className="text-blue-600">LMS</span></span>
        </div>
        <div className="flex items-center gap-4">
          {user && (
            <div className="text-right hidden sm:block mr-2">
              <p className="text-sm font-black text-high-contrast leading-none">{user.name}</p>
              <p className="text-[10px] text-low-contrast uppercase font-black tracking-widest mt-1">{user.role}</p>
            </div>
          )}
          <button onClick={toggleTheme} className="w-11 h-11 rounded-xl bg-[var(--card)] shadow-sm flex items-center justify-center border border-slate-200 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
            {theme === Theme.LIGHT ? '🌙' : '☀️'}
          </button>
          {user && <button onClick={() => window.location.reload()} className="text-[10px] font-black uppercase tracking-widest text-low-contrast hover:text-red-500 transition-colors ml-2">Logout</button>}
        </div>
      </nav>

      <main className="max-w-6xl mx-auto px-6 mt-4">
        {view === 'home' && (
          <div className="flex flex-col items-center justify-center min-h-[70vh] text-center space-y-12">
            <div className="space-y-6">
              <h1 className="text-7xl font-black tracking-tight leading-[1.05] text-high-contrast">
                Modern Assessment.<br/><span className="text-blue-600">Intelligent Results.</span>
              </h1>
              <p className="text-xl text-low-contrast max-w-2xl mx-auto font-medium leading-relaxed">
                Empowering educators with AI-generated testing and students with immediate, high-fidelity feedback.
              </p>
            </div>
            <div className="flex gap-5 w-full max-w-xl">
              <button onClick={() => { setRole('teacher'); setView('login'); }} className="flex-1 h-16 bg-blue-600 text-white rounded-2xl font-black text-lg shadow-2xl shadow-blue-600/30 hover:scale-105 transition-all">Teacher Login</button>
              <button onClick={() => { setRole('student'); setView('login'); }} className="flex-1 h-16 bg-[var(--card)] border-2 border-slate-200 dark:border-slate-800 text-high-contrast rounded-2xl font-black text-lg hover:scale-105 transition-all">Student Portal</button>
            </div>
          </div>
        )}

        {view === 'login' && (
          <div className="max-w-md mx-auto py-12">
            <div className="q-card p-10 border-slate-200 dark:border-slate-800">
              <h2 className="text-3xl font-black mb-2 text-high-contrast">{role === 'teacher' ? 'Admin Gateway' : 'Student Access'}</h2>
              <p className="text-sm text-low-contrast mb-8 font-semibold uppercase tracking-widest">Authentication Required</p>
              <form onSubmit={handleLogin} className="space-y-5">
                <div className="space-y-1">
                  <label className="text-[10px] font-black uppercase tracking-widest text-low-contrast ml-1">Identity Name</label>
                  <input required name="name" type="text" className="w-full h-14 px-5 rounded-2xl bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-800 outline-none focus:border-blue-500 font-bold text-high-contrast transition-all" placeholder="Johnathan Doe" />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black uppercase tracking-widest text-low-contrast ml-1">Serial ID</label>
                  <input required name="id" type="text" className="w-full h-14 px-5 rounded-2xl bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-800 outline-none focus:border-blue-500 font-bold text-high-contrast transition-all" placeholder="ID-8829" />
                </div>
                {role === 'teacher' && (
                  <div className="space-y-1">
                    <label className="text-[10px] font-black uppercase tracking-widest text-low-contrast ml-1">Administrative Pass</label>
                    <input required name="password" type="password" className="w-full h-14 px-5 rounded-2xl bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-800 outline-none focus:border-blue-500 font-bold text-high-contrast transition-all" placeholder="••••••••" />
                  </div>
                )}
                {error && <p className="text-red-500 text-sm font-black text-center">{error}</p>}
                <button type="submit" className="w-full h-16 bg-blue-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-blue-600/20 mt-4">Verify Identity</button>
                <button type="button" onClick={() => setView('home')} className="w-full text-center text-xs font-black uppercase tracking-widest text-low-contrast hover:text-high-contrast transition-colors pt-2">Cancel Access</button>
              </form>
            </div>
          </div>
        )}

        {view === 'teacher-dash' && <TeacherDash />}
        {view === 'student-dash' && <StudentDash />}
        {view === 'review-detail' && <ReviewDetailModal />}

        {view === 'test-creator' && (
          <div className="max-w-3xl mx-auto py-8">
            <h2 className="text-4xl font-black mb-8 text-high-contrast">{editTestId ? 'Edit Configuration' : 'Test Generation'}</h2>
            <form onSubmit={handleSaveTest} className="q-card p-10 space-y-8 border-slate-200 dark:border-slate-800">
              <div className="space-y-2">
                <label className="text-xs font-black uppercase tracking-[0.2em] text-low-contrast">Test Designation</label>
                <input required name="title" defaultValue={tests.find(t => t.id === editTestId)?.title} className="w-full h-16 px-6 rounded-2xl bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-800 outline-none focus:border-blue-500 font-black text-2xl text-high-contrast" placeholder="Exam Title" />
              </div>

              {!editTestId && (
                <div className="space-y-2">
                  <label className="text-xs font-black uppercase tracking-[0.2em] text-low-contrast">Source Curriculum Material</label>
                  <textarea required name="text" className="w-full h-72 p-6 rounded-2xl bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-800 outline-none focus:border-blue-500 resize-none font-medium leading-relaxed text-high-contrast" placeholder="Paste study content here..." />
                </div>
              )}

              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-xs font-black uppercase tracking-[0.2em] text-low-contrast">Item Count</label>
                  <input required type="number" name="count" defaultValue={10} min={1} max={50} disabled={!!editTestId} className="w-full h-14 px-6 rounded-2xl bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-800 outline-none focus:border-blue-500 font-black text-high-contrast" />
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-black uppercase tracking-[0.2em] text-low-contrast">Window (Min)</label>
                  <input required type="number" name="timer" defaultValue={tests.find(t => t.id === editTestId)?.timerMinutes || 20} min={1} max={180} className="w-full h-14 px-6 rounded-2xl bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-800 outline-none focus:border-blue-500 font-black text-high-contrast" />
                </div>
              </div>

              {error && <p className="text-red-500 font-black">{error}</p>}

              <div className="flex gap-4 pt-6">
                <button type="button" onClick={() => setView('teacher-dash')} className="flex-1 font-black text-low-contrast hover:text-high-contrast">Discard</button>
                <button disabled={isGenerating} type="submit" className="flex-[3] h-16 bg-blue-600 text-white rounded-2xl font-black text-xl shadow-2xl shadow-blue-500/30">
                  {isGenerating ? 'Synthesizing...' : editTestId ? 'Update Settings' : 'Generate & Deploy'}
                </button>
              </div>
            </form>
          </div>
        )}

        {view === 'test-taking' && activeTest && (
          <div className="max-w-3xl mx-auto pb-40">
             <header className="sticky top-0 bg-[var(--bg)]/80 backdrop-blur-xl py-6 z-50 flex justify-between items-center mb-10 border-b border-slate-200 dark:border-slate-800">
                <div className="space-y-1">
                  <h3 className="font-black text-2xl tracking-tight text-high-contrast">{activeTest.title}</h3>
                  <div className="flex items-center gap-3">
                    <span className="text-[10px] font-black uppercase tracking-widest text-blue-600 dark:text-blue-400">Question {Object.keys(answers).length} / {activeTest.questions.length}</span>
                    <div className="w-32 h-1.5 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                      <div className="h-full bg-blue-500 transition-all" style={{ width: `${(Object.keys(answers).length / activeTest.questions.length) * 100}%` }}></div>
                    </div>
                  </div>
                </div>
                <div className={`px-8 py-3 rounded-2xl font-mono text-2xl font-black shadow-lg ${timeLeft < 60 ? 'bg-red-500 text-white animate-pulse shadow-red-500/20' : 'bg-slate-900 text-white dark:bg-white dark:text-slate-900 shadow-slate-900/20'}`}>
                  {isPreviewMode ? 'PREVIEW' : `${Math.floor(timeLeft / 60)}:${String(timeLeft % 60).padStart(2, '0')}`}
                </div>
             </header>
             <div className="space-y-8">
                {activeTest.questions.map((q, i) => (
                  <QuestionLayout 
                    key={q.id} 
                    question={q} 
                    index={i} 
                    selected={answers[q.id]} 
                    onSelect={(label: string) => setAnswers({...answers, [q.id]: label})} 
                  />
                ))}
             </div>
             <div className="fixed bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-[var(--bg)] via-[var(--bg)] to-transparent pointer-events-none">
                <div className="max-w-3xl mx-auto pointer-events-auto">
                  <button onClick={handleTestSubmit} className="w-full h-16 bg-blue-600 text-white rounded-[1.5rem] font-black text-xl shadow-2xl shadow-blue-600/40 hover:scale-[1.02] active:scale-95 transition-all">
                    {isPreviewMode ? 'Close Preview' : 'Submit Final Answers'}
                  </button>
                </div>
             </div>
          </div>
        )}

        {view === 'result-view' && activeResult && (
          <div className="max-w-2xl mx-auto py-20 text-center animate-in">
             <div className={`w-36 h-36 rounded-[2.5rem] flex items-center justify-center text-4xl font-black mx-auto mb-10 shadow-2xl border-4 border-white dark:border-slate-800 ${getScoreColor(activeResult.score)}`}>
               {activeResult.score}%
             </div>
             <h2 className="text-5xl font-black tracking-tight mb-4 text-high-contrast">Excellent, {user?.name.split(' ')[0]}!</h2>
             <p className="text-low-contrast font-semibold text-lg max-w-lg mx-auto mb-12 uppercase tracking-widest">Assessment Recorded</p>

             <div className="q-card p-10 text-left border-blue-100 dark:border-blue-900/30 bg-blue-50/50 dark:bg-blue-950/20 mb-12">
               <h4 className="font-black text-blue-700 dark:text-blue-300 text-[10px] uppercase tracking-[0.25em] mb-6 flex items-center gap-3">
                 <span className="w-2 h-2 rounded-full bg-blue-500"></span>
                 Mentor Analysis
               </h4>
               <p className="text-lg font-medium leading-relaxed text-high-contrast italic opacity-90 whitespace-pre-line">"{activeResult.aiFeedback}"</p>
             </div>

             <div className="flex flex-col sm:flex-row gap-4">
               <button onClick={() => setView('review-detail')} className="flex-1 h-16 border-2 border-slate-200 dark:border-slate-800 text-high-contrast rounded-2xl font-black hover:bg-slate-50 dark:hover:bg-slate-800 transition-all">Review Submissions</button>
               <button onClick={() => setView('student-dash')} className="flex-1 h-16 bg-slate-900 text-white dark:bg-white dark:text-slate-900 rounded-2xl font-black shadow-xl">Return to Dashboard</button>
             </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;
